b = &quot; &lt;&lt; b &lt;&lt; &#x27;
&#x27;; &#125;private: int b&#123; 10 &#125;;&#125;;int main() &#123; int a&#123; 5 &#125;, b&#123; 10 &#125;; Collable_class C_instance; call_func( C_instance, a ); return 0;&#125; 記得要引入標頭檔 &lt;functional&gt;。 語法與相關函式這次試著改了文章的順序，先教大家怎麼用，再去講內部實現的概念，主要是因為有些人比較在意該怎麼用與何時使用，並不是太在意裡面怎麼實作的。再來雖然核心概念差不多，但不同編譯器實作的方法還是會稍微不太一樣。 語法與重要定義語法其實挺簡單的，基本上就是 std::function&lt;回傳型態(參數列)&gt; 實例名 &#x3D; 初始化器 初始化器就是拿來初始化的東西，前面也提到了只要是可呼叫的物件都可以拿來用，看看 cppreference 上的例子： 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566#include &lt;functional&gt;#include &lt;iostream&gt;struct Foo &#123; Foo( int num ) : num_( num ) &#123;&#125; void print_add( int i ) const &#123; std::cout &lt;&lt; num_ + i &lt;&lt; &#x27;
&#x27;; &#125; int num_;&#125;;//一般函式void print_num( int i ) &#123; std::cout &lt;&lt; i &lt;&lt; &#x27;
&#x27;;&#125;//可呼叫的Struct，有重載operator()struct PrintNum &#123; void operator()( int i ) const &#123; std::cout &lt;&lt; i &lt;&lt; &#x27;
&#x27;; &#125;&#125;;int main() &#123; // std::function 儲存一個回傳 void 的 function，參數吃一個int std::function&lt;void( int )&gt; f_display = print_num; f_display( -9 ); // std::function 儲存一個回傳 void 的 lambda，參數沒吃東西 std::function&lt;void()&gt; f_display_42 = []() &#123; print_num( 42 ); &#125;; f_display_42(); // std::function 儲存 std::bind 回傳的 function，function 回傳 void，參數列不吃東西 std::function&lt;void()&gt; f_display_31337 = std::bind( print_num, 31337 ); f_display_31337(); // std::function 儲存一個 member function，這個 member function 回傳 void，參數吃一個 Foo和一個 int std::function&lt;void( const Foo &amp;, int )&gt; f_add_display = &amp;Foo::print_add; const Foo foo( 314159 ); f_add_display( foo, 1 ); f_add_display( 314159, 1 ); // std::function 儲存一個 accessor std::function&lt;int( const Foo &amp; )&gt; f_num = &amp;Foo::num_; std::cout &lt;&lt; &quot;num_: &quot; &lt;&lt; f_num( foo ) &lt;&lt; &#x27;
&#x27;; // std::function 儲存一個 std::bind 回傳的 function，std::bind 吃一個 member function 和實例 std::function&lt;void( int )&gt; f_add_display2 = std::bind( &amp;Foo::print_add, foo,std::placeholders::_1 ); f_add_display2( 2 ); // std::function 儲存一個 std::bind 回傳的 function，std::bind 吃一個 member function 和實例的位址 std::function&lt;void( int )&gt; f_add_display3 = std::bind( &amp;Foo::print_add, &amp;foo,std::placeholders::_1 ); f_add_display3( 3 ); // std::function 儲存一個可呼叫的物件 std::function&lt;void( int )&gt; f_display_obj = PrintNum(); f_display_obj( 18 ); auto factorial = []( int n ) &#123; // store a lambda object to emulate &quot;recursive lambda&quot;; aware of extra overhead std::function&lt;int( int )&gt; fac = [&amp;]( int n ) &#123; return ( n &lt; 2 ) ? 1 : n * fac( n - 1 ); &#125;; // note that &quot;auto fac = [&amp;](int n)&#123;...&#125;;&quot; does not work in recursive calls return fac( n ); &#125;; for ( int i&#123; 5 &#125;; i != 8; ++i ) &#123; std::cout &lt;&lt; i &lt;&lt; &quot;! = &quot; &lt;&lt; factorial( i ) &lt;&lt; &quot;; &quot;; &#125;&#125; 從上例可見可儲存的東西挺多的，只要是可呼叫物件基本上都可以儲存。不過不知道大家有沒有覺得有其中一個很奇怪，那就是 std::function&lt;int( const Foo &amp; )&gt; f_num = &amp;Foo::num_;，右邊的這個 &amp;Foo::num_ 是個資料成員指標，那為什麼這個可以拿來初始化 std::function 呢? 讓我們回顧一下最一開始的定義： std::funtion 這個類別模板提供了多型的 wrapper，通常拿來包函式指標。 這個 Wrapper 可以儲存，複製，和透過 () 呼叫任何的可呼叫物件，並允許 function 為一級函式。 接下來就有個問題了，到底什麼是可呼叫物件呢? 定義如下： 一個可呼叫物件指的是一個物件擁有可呼叫的型態 ( 20.14.3-4 ) 所以接下來的問題就變成「什麼是可呼叫的型態」了，定義如下： 可呼叫型態指的是 function object type 或是一個資料成員的指標 ( 20.14.3-3 ) 這樣答案就很明顯了，&amp;Foo::num_ 是個資料成員指標，代表他是可呼叫的物件，因此可以拿來初始化 std::function。 至於 function object type 指的則是一種在 function call 內可以是後序表達式(postfix-expression) 的物件型態，至於什麼是後序表達式這邊就先不介紹了，再寫下去會有點偏題。 那麼既然知道了什麼是 function object type，那麼 function object 很直覺的就是那些型態是 function object type 的物件了。 簡單來說，可呼叫物件(collable object) 的意思就是某個有明確定義動作的物件，對 function object 來說就是透過 () 來呼叫的相對應的物件，對函式指標來說就是呼叫相對應的函式，對成員指標來說就是拜訪相對應的成員。 複雜的定義大概就這樣，那麼 std::function 的使用時機在前言的地方也提到了，std::function 主要就是為了泛用性，消除型態上面的差異而出現的東西。 代價也不大，std::function 並不肥，能使用的話就盡量使用吧。 相關函式在 C++17、C++20 時有部分的相關函式被刪除了，那些被刪除的函式本篇就不介紹了，主要介紹那些仍可使用的，有興趣的可以到 cppreference 上看。 這邊的內容除了怎麼使用以外可能也會扯到內部的結構， 接下來的 fn 代表某個 std::function 的 instance，簡單來說就是 std::function&lt;void()&gt; fn = 某個 callable object 這樣，只是一個代稱方便大家理解。 建構子 基本上內部寫好的建構子有五個，加上最新的 Defect Report(C++23) 內提出的方法有六個 1、2： 12function() noexcept; // 1function( std::nullptr_t ) noexcept; // 2 上面這兩個(1、2) 會建構出空的 std::function 3、4： 12function( const function&amp; other ); // 3function( function&amp;&amp; other ) noexcept; // 4 上面這兩個(3、4) 會將 other 的 target 複製(3) 或移動(4) 到 *this。 簡單來說就是把對象包裝起來的東西移動或複製到自己身上。如果 other 是空的，*this 也會是空的。 另外，移動(4) 後的 other 會處於有效但未指定的狀態。 5： 12template&lt; class F &gt;function( F f ); // 5 前面的 4 個都是用 std::function 來初始化，這個可以說是最常用的了，這個建構子也是 std::function 可以做到高泛用性的原因。 基本上就是用我們給的東西來初始化內部的 target，如果想看內部的實作可以直接往下拉到內部概念那邊看，因為這扯到整個結構的問題。 不過要注意的是如果 std::function 的回傳型態是個繫結到某個沒有 trailing-return-type 的 lambda 所回傳的 reference type，由於 auto deduction 的關係，這種 lambda 回傳的型態一定會是個 prvalue，因此 std::function 的回傳型態的 reference 會繫結到一個暫時物件，但這個暫時物件的生命週期會在 std::function::operator() 回傳時結束，因此會變一個懸掛的 reference(dangling reference)。 例子： 12std::function&lt;const int&amp;()&gt; F([]&#123; return 42; &#125;);int x = F(); // Undefined behavior: the result of F() is a dangling reference 6： 12template&lt; class F &gt;function( F&amp;&amp; f ); // 6 最後這個是最近更新的，還不在標準裡面，但有在 C++23 的草案裡面，如果想看舊版的規範可以到這裡看，另外裡面還有對編譯器實作的建議、Postconditions 和 Preconditions 等等，有興趣的也可以進來看。 具體上的原因可以到 Defect Report(C++23) 看，簡單來說就是 operator= 吃的是 F&amp;&amp; f，而如果 constructor 用複製的會有一些 Value Categories 上的影響。 在新版的實作內，我們會利用 std::forward&lt;F&gt;(f) 來初始化 target，target 的型態會是 std::decay&lt;F&gt;::type。 如果 f 是個 null 的 function pointer、member pointer 或一個由 std::function 特化的空值，那麼 *this 會是一個空的 std::function。 這個 constructor 不會參加多載解析(Overload resolution)，除非 target 的 type 不是 std::function，而且對於那些參數的型態 Args… 來說，它的 lvalue 是可呼叫的而且回傳的型態 R 也是可呼叫的型態。 如果 target 的 type 不能複製，或者初始化的格式不對，那麼這是個 ill-formed。 解構子 destructor 就相對沒那麼複雜了，但要注意一下解構的時候的時候會連 target 一起解構。 operator&#x3D; 基本上內部寫好的有五個 1： 1function&amp; operator= ( const function&amp; other ); 上面這個會 copy other 的 target 到 *this 的 target。 2： 1function&amp; operator=( function&amp;&amp; other ); 上面這個會移動 other 的 target 到 *this 的 target，此時 other 會處於未定義的有效狀態。 3: 1function&amp; operator=( std::nullptr_t ) noexcept; 上面這個會把目前的 target 解構，讓 *this 回復為空。 4： 12template&lt; class F &gt;function&amp; operator=( F&amp;&amp; f ); 上面這個將會把 *this 的 target 設為可呼叫的 f。 除非 f 對於參數的類型 Args… 和回傳的型態 R 是可呼叫的，不然這個運算符不會執行 Overload Resolution。 5： 12template&lt; class F &gt;function&amp; operator=( std::reference_wrapper&lt;F&gt; f ) noexcept; 上面這個會把 f 的 target 複製給 *this 的 target。 operator bool std::function 的 operator bool 會檢查 *this 的 target 是否為空，如果非空就回傳 true，如果是空的就回傳 false。 例子： 1234567891011121314151617181920212223242526#include &lt;functional&gt;#include &lt;iostream&gt;void sampleFunction() &#123;&#125;void checkFunc( std::function&lt;void()&gt; &amp;func ) &#123; // 利用 operator bool 來確認 std::function 是否為空。 if ( func ) &#123; std::cout &lt;&lt; &quot;Function is not empty!
&quot;; &#125; else &#123; std::cout &lt;&lt; &quot;Function is empty. Nothing to do.
&quot;; &#125;&#125;int main() &#123; std::function&lt;void()&gt; f1; std::function&lt;void()&gt; f2( sampleFunction ); std::cout &lt;&lt; &quot;f1: &quot;; checkFunc( f1 ); // std::function 為空，進入 else std::cout &lt;&lt; &quot;f2: &quot;; checkFunc( f2 ); // std::function 非空，進入 if&#125; operator() R operator()( Args… args ) const; std::function 的 operator() 會傳入參數，呼叫儲存的 callable object。 例子： 1234567891011121314151617181920212223#include &lt;functional&gt;#include &lt;iostream&gt;void call( std::function&lt;int()&gt; f ) // std::function 可以 passed by value&#123; std::cout &lt;&lt; f() &lt;&lt; &#x27;
&#x27;;&#125;int normal_function() &#123; return 42;&#125;int main() &#123; int n = 1; std::function&lt;int()&gt; f = [&amp;n]() &#123; return n; &#125;; call( f ); n = 2; call( f ); f = normal_function; call( f );&#125; swap 語法： fn.swap(目標) 作用： 交換所存的 callable object 例子： 12345678910111213141516171819202122#include &lt;functional&gt;#include &lt;iostream&gt;void fn1() &#123; std::cout &lt;&lt; &quot;fn 1
&quot;;&#125;void fn2() &#123; std::cout &lt;&lt; &quot;fn 2
&quot;;&#125;int main() &#123; std::function&lt;void()&gt; s1&#123; fn1 &#125;; std::function&lt;void()&gt; s2&#123; fn2 &#125;; s1(), s2(); // fn1 
 fn2 puts( &quot;&quot; ), s1.swap( s2 ); s1(), s2(); // fn2 
