&#x27;; // PFvdE&#125; target 12345template&lt; class T &gt;T* target() noexcept; // (1)//----------------------------------//template&lt; class T &gt;const T* target() const noexcept // (2) 如果 target_type() == typeid(T)，回傳一個指向儲存的 target 的 pointer，否則回傳一個 null pointer。 例子： 12345678910111213141516171819202122232425262728293031323334353637383940414243444546#include &lt;functional&gt;#include &lt;iostream&gt;int f( int, int ) &#123; puts( &quot;calling f&quot; ); return 1;&#125;int g( int, int ) &#123; puts( &quot;calling g&quot; ); return 2;&#125;void sampleFunction() &#123; puts( &quot;calling ssample Function&quot; );&#125;void test( const std::function&lt;int( int, int )&gt; &amp;arg ) &#123; std::cout &lt;&lt; &quot;test function: &quot;; if ( arg.target&lt;std::plus&lt;int&gt;&gt;() ) std::cout &lt;&lt; &quot;it is plus
&quot;; if ( arg.target&lt;std::minus&lt;int&gt;&gt;() ) std::cout &lt;&lt; &quot;it is minus
&quot;; int ( *const *ptr )( int, int ) = arg.target&lt;int ( * )( int, int )&gt;(); if ( ptr &amp;&amp; *ptr == f ) &#123; std::cout &lt;&lt; &quot;it is the function f
&quot;; ( *ptr )( 1, 1 ); &#125; if ( ptr &amp;&amp; *ptr == g ) &#123; std::cout &lt;&lt; &quot;it is the function g
&quot;; ( *ptr )( 1, 1 ); &#125;&#125;int main() &#123; test( std::function&lt;int( int, int )&gt;( std::plus&lt;int&gt;() ) ); test( std::function&lt;int( int, int )&gt;( std::minus&lt;int&gt;() ) ); test( std::function&lt;int( int, int )&gt;( f ) ); test( std::function&lt;int( int, int )&gt;( g ) ); std::function&lt;void()&gt; fn = sampleFunction; void ( **fn_ptr )() = fn.target&lt;void ( * )()&gt;(); ( *fn_ptr )();&#125; Deduction Guides 模板推導指引在 C++17 時有個叫 CTAD 的東西出現了，不知道的朋友可以先到 cppreference 上看，或看一下 TSJW的文章。 簡單來說就是讓模板自己推定型態的技術，舉個例子：std::vector&lt;int&gt; vec = &#123;5&#125;; 可以寫成 std::vector vec = &#123;5&#125;; 這樣，int 可以由編譯器推導出來。雖然看起來好像很簡單，但後面牽扯到的東西挺多的，像是自訂的型態等等，這邊不討論太多，因為不是今天的主題 那麼 std::function 自然也會有這個技術了，畢竟也是一個通過模板來實現的東西。 內部有兩個定義： 12template&lt;class R, class... ArgTypes&gt;function(R(*)(ArgTypes...)) -&gt; function&lt;R(ArgTypes...)&gt;; // (1) 上面這個讓 std::function 可以自動推斷出一般函式的型態。 12template&lt;class F&gt;function(F) -&gt; function&lt;/*see below*/&gt;; // (2) 而第二個這個，只有當 &amp;F::operator() 不是拿來當計算的操作數，語法合法，且 decltype(&amp;F::operator()) 的形式是 R(G::*)(A...) (可有 cv限定詞、noexcept、lvalue reference)，用於某些 class type G 時，會進入 Overload Resolution。 看起來很複雜，但簡單來說就是 decltype(&amp;F::operator()) 是有效的，此時的型態會被推導為 std::function&lt;R(A...)&gt;。 例子： 12345678#include &lt;functional&gt;int func( double ) &#123; return 0; &#125;int main() &#123; std::function f&#123; func &#125;; // 利用第一個規則推導出 std::function&lt;int(double)&gt; int i = 5; std::function g = [&amp;]( double ) &#123; return i; &#125;; // 利用第二個規則推導出 std::function&lt;int(double)&gt;&#125; 不過未來這個 Deduction Guides 可能還會改變，尤其是在 std::function 支援 noexcept 之後。 內部概念內部概念我大概會講一下架構，然後帶大家看一下 GCC 上的優化與 code。 接下來的內容主要參考了 Raymond 的兩篇文章、 Stackoverflow 上的講解與 jerrt_fuyi 的文章：連結 1、連結 2、連結 3、連結 4，有興趣的可以進去看看原文。 架構我們的目的是消除型態，雖然有很多不同的方法能達到這個目的，但概念上的架構上主要會有一個可呼叫物件的基類，之後利用模板，由這個基類衍生出不同的可呼叫物件的實例，之後 std::function 再去存取這個實例的指標，大概會像這樣： 1234567891011121314151617181920212223242526272829303132333435363738394041#include &lt;memory&gt;struct callable_base &#123; callable_base() = default; virtual ~callable_base() &#123;&#125; virtual bool invoke( int, char * ) = 0; virtual std::unique_ptr&lt;callable_base&gt; clone() = 0;&#125;;template &lt;typename T&gt;struct callable : callable_base &#123; T m_t; callable( T const &amp;t ) : m_t( t ) &#123;&#125; callable( T &amp;&amp;t ) : m_t( move( t ) ) &#123;&#125; bool invoke( int a, char *b ) override &#123; return m_t( a, b ); &#125; std::unique_ptr&lt;callable_base&gt; clone() override &#123; return make_unique&lt;callable&gt;( m_t ); &#125;&#125;;struct function &#123; std::unique_ptr&lt;callable_base&gt; m_callable; template &lt;typename T&gt; function( T &amp;&amp;t ) : m_callable( new callable&lt;decay_t&lt;T&gt;&gt;( forward&lt;T&gt;( t ) ) ) &#123; &#125; function( const function &amp;other ) : m_callable( other.m_callable ? other.m_callable-&gt;clone() : nullptr ) &#123; &#125; function( function &amp;&amp;other ) = default; bool operator()( int a, char *b ) &#123; return m_callable-&gt;invoke( a, b ); &#125;&#125;; 這只是一個簡單的偽代碼，可能無法編譯，callable_base 提供了解構、呼叫、複製等動作的介面，再由各種可呼叫物件自行去實作。 在上面使用了 unique_ptr，這會讓複製建構子有些難做，因為 unique_ptr 無法複製，因此在實作上通常會使用原生的指標，並自行管理資源的分配，比較複雜，但也比較方便我們優化。 可以看看另一個人幫忙做的簡化版本，這是 StackOverflow 上有人做的，他簡化的是 Ubuntu 14.04 gcc 4.8 上的 std::function，這邊他選擇將 callable_base 那些繼承的東西給簡化掉了，比較注重在內部消除型態的實現上，我幫忙整理了一下並加上了一些註解： 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111#include &lt;iostream&gt;#include &lt;memory&gt;template &lt;typename T&gt;class function;template &lt;typename R, typename... Args&gt;class function&lt;R( Args... )&gt; &#123; // 這些 function pointer type 是拿來消除型態的，下面這些 void* 都是從某種 function type 轉過來的 using invoke_fn_t = R ( * )( void *, Args &amp;&amp;... ); //拿來呼叫的函式指標 using construct_fn_t = void ( * )( void *, void * ); //建構子的函式指標 using destroy_fn_t = void ( * )( void * ); //解構子的函式指標 using fn_ptr = void ( * )(); //普通的函式指標 // 因為有些 callable 物件無法直接被轉換成 function pointer，像是有捕捉東西的 lambda，所以我們需要一個泛型的函式幫助我們將其轉換成指標並呼叫。 template &lt;typename Functor&gt; static R invoke_fn( Functor *fn, Args &amp;&amp;...args ) &#123; return ( *fn )( std::forward&lt;Args&gt;( args )... ); &#125; template &lt;typename Functor&gt; static void construct_fn( Functor *construct_dst, Functor *construct_src ) &#123; // Functor type 需要是用複製建構的，這個是 Placement new，沒看過的可以去看一下用法。 new ( construct_dst ) Functor( *construct_src ); &#125; template &lt;typename Functor&gt; static void destroy_fn( Functor *f ) &#123; f-&gt;~Functor(); &#125; // 這些 pointer 拿來儲存行為 invoke_fn_t invoke_f; // 儲存呼叫韓式的指標 construct_fn_t construct_f; // 儲存建構子的函式指標 destroy_fn_t destroy_f; // 儲存解構子的函式指標 // 這邊要把 Functor 的型態消除，並將它存到 void*。 因此我們也要能夠拿到儲存的空間。 std::unique_ptr&lt;fn_ptr[]&gt; data_ptr; // 「 函式指標的陣列 」的 unique_ptr std::size_t data_size; // 能夠儲存的空間 public: // 空的 function function() : invoke_f( nullptr ), construct_f( nullptr ), destroy_f( nullptr ), data_ptr( nullptr ), data_size( 0 ) &#123;&#125; // 從任何的 Functor 來建構的 function template &lt;typename Functor&gt; function( Functor f ) // 特化 function 並利用轉型消除它的型態 : invoke_f( reinterpret_cast&lt;invoke_fn_t&gt;( invoke_fn&lt;Functor&gt; ) ), // 初始化呼叫指標 construct_f( reinterpret_cast&lt;construct_fn_t&gt;( construct_fn&lt;Functor&gt; ) ), // 初始化建構指標 destroy_f( reinterpret_cast&lt;destroy_fn_t&gt;( destroy_fn&lt;Functor&gt; ) ), // 初始化解構指標 data_ptr( new fn_ptr[sizeof( Functor )] ), // 初始化資料陣列的指標 data_size( sizeof( Functor ) ) &#123; // 初始化儲存空間的大小 // 複製 functor 到內部拿來儲存行為的指標 this-&gt;construct_f( this-&gt;data_ptr.get(), reinterpret_cast&lt;void *&gt;( &amp;f ) ); &#125; // 複製建構子 function( function const &amp;rhs ) : invoke_f( rhs.invoke_f ), construct_f( rhs.construct_f ), destroy_f( rhs.destroy_f ), data_size( rhs.data_size ) &#123; if ( this-&gt;invoke_f ) &#123; //如果 target 非空，那就複製 target。 this-&gt;data_ptr.reset( new fn_ptr[this-&gt;data_size] ); this-&gt;construct_f( this-&gt;data_ptr.get(), rhs.data_ptr.get() ); &#125; &#125; ~function() &#123; if ( data_ptr != nullptr ) &#123; this-&gt;destroy_f( this-&gt;data_ptr.get() ); &#125; &#125; // 拿來呼叫的運算子 R operator()( Args &amp;&amp;...args ) &#123; return this-&gt;invoke_f( this-&gt;data_ptr.get(), std::forward&lt;Args&gt;( args )... ); &#125;&#125;;// examplesint main() &#123; int i = 0; auto fn = [i]( const std::string &amp;s ) mutable &#123; std::cout &lt;&lt; ++i &lt;&lt; &quot;. &quot; &lt;&lt; s &lt;&lt; std::endl; &#125;; fn( &quot;first&quot; ); // 1. first fn( &quot;second&quot; ); // 2. second // 利用 lambda 建構 ::function&lt;void( const std::string &amp; )&gt; f( fn ); f( &quot;third&quot; ); // 3. third // 利用別的 function 來建構 ::function&lt;void( const std::string &amp; )&gt; g( f ); f( &quot;forth - f&quot; ); // 4. forth - f g( &quot;forth - g&quot; ); // 4. forth - g // 利用有捕捉一個 std::string 的 lambda 建構 std::string x( &quot;xxxx&quot; ); ::function&lt;void()&gt; h( [x]() &#123; std::cout &lt;&lt; x &lt;&lt; std::endl; &#125; ); h(); ::function&lt;void()&gt; k( h ); k(); ::function&lt;int()&gt; ifn = []() &#123; return 5; &#125;; int xx = ifn(); std::cout &lt;&lt; xx; // 5 return 0;&#125; 雖然因為簡化的關係和 gcc 裡面寫的已經有點不太一樣了，但主要的核心概念仍一樣，就是透過模板來消除型態。 內部實作與優化 前言接下來的內容有很多地方都來自 jerry_fuyi 的文章，基本上是引用過來，改寫一些部分，自己讀了很久，希望多加一些解釋，抓一些重點出來後，大家能更容易理解，如果看不習慣我的也很建議回去讀讀原文，因為真的寫得蠻好蠻詳細的。 而如果你已經看得很累了，那麼可以去休息一下，因為接下來的內容會比較生硬 XD 看完了前面約略的概念後各位可能覺得這個東西就這樣了，其實沒那麼簡單，還有很多隱藏的問題(雖然前面可能先講了答案XD，但大家可能沒想過會有這些問題)，例如，函式不是一個固定大小的對象，但 class 是，我們用 class 來包裝不同的函式，卻要有相同的大小，不會有問題嗎? 還有其他很多的小問題，導致這個東西一直到 C++23 都還拿出來被討論，前面的建構子就是其中一項，有些東西可能會牽扯到 ABI Break，蠻複雜的。 實作前的想法std::function 能儲存不同的可呼叫物件，表示有多態性，這我們前面使用了 virtual function 與繼承解決了，這是個簡單、直覺且有效的方法，但這個方法會用到動態內存，很多情況下這是種浪費，像是一個沒捕捉東西的 lambda，這種情況下他只有一個 char 的大小，但我們卻為了它去呼叫了分配動態內存的函式。 於是我們就需要想辦法避免這種浪費，剛剛說了 std::function 的大小是固定的，但是這個大小是可以讓我們自己定的，所以我們可以在 std::function 裡面放一個空白且大小適中的 field 來存這種小對象，來避免呼叫到動態內存。 而對於更大的可呼叫物件，雖然放不進這個 field，但可以放這個可呼叫物件的指標，這種 TDM 的結構可以用 union 來做。 這種小物件直接儲存，大對象才放在 heap 上並儲存指標的方法叫做 small object optimization。 在利用了繼承的實作中，可呼叫物件被包裝在一個子類裡面，std::function 會持有一個其父類的指標，但為了效率，我們需要把剛剛那個空白的 field 與這個指針用 union 包裝起來。 既然用了 union，在不確定這個 union 存的是什麼之前，當然不能去呼叫裡面的東西，因此這樣的設計我們就不能使用繼承來去消除型態了。 於是我們需要想其他的方法來達成多態性，而這邊大家可以想一下 virtual function 是怎麼實現的，有 virtual function 的 class 裡面會有個 vptr，指向一個 vtable，這個 vtable 有很多個 slot，裡面有指向 type_info 對象的指標和函式指標。 發現了嗎? 就是函式指標，函式指標也是一個能幫助我們實現多態性的東西，如果你是想在 C 裡面實現多態，比較方便的方法也是在 struct 內直接放 function pointer，因此我們主要會使用 function pointer 來實作。 開始實作基本上 std::function 是個模板類，模板參數就是一個 type，注意是一個 type，不是好幾種 type，以這個例子來說： 1std::function&lt;int(double)&gt; f; f 是一個可以呼叫的對象，參數吃一個 double，回傳一個 int。 你可能會覺得奇怪，這邊這樣不就有兩個 type 了嗎? 怎麼還說是一個 type，其實 int(double) 自己就是一個 type，它是一種 function type，但要注意不是 function pointer。 接下來我會帶大家看一下 gcc 的實作 (待補，被高微殘害中QQ) 參考資料1. std::function (cppreference) (文章部分來源) 2. Expressions 3. General utilities library 4. Function Definitions 5. How is std::function implemented? 6. Inside std::function, part 1: The basic idea 7. Function passed as template argument 8. What is std::function in C++, and why we need them? 9. Should I use std::function or a function pointer in C++? 10. C++ 11 std::function和std::bind使用詳解 11. What are preconditions and postconditions? 12. Overload resolution 13. Class template argument deduction (CTAD) 14. 潮．C++17 | Class Template Argument Deduction 和 Deduction Guide 類別樣版參數推導 15. Difference between Undefined Behavior and Ill-formed, no diagnostic message required 16. C++ typeid關鍵字詳解 17. C++11 Type Deduction With std::function 18. template argument type deduction from std::function return type with lambda 19. Argument type auto deduction and anonymous lambda functions 20. Type deduction for std::function 21. 剖析STD::FUNCTION接口与实现 (文章部分來源) 22. checking invariants in C++ 23. Example of C++ class invariant 24. When to make a type non-movable in C++11? 25. 简析 std::function 实现原理

礦坑系列 ── 值類別 Value Categoraries 礦坑系列首頁：首頁 hackmd 版首頁：首頁 前言原本想說要一個禮拜寫一篇礦坑，結果發現這種文都要花很多的時間，好像一篇一個月就差不多了XD 這篇文章特別感謝 Kris van Rens，我寫信問了他許多問題，他也很耐心的回答我XD 文章內容有許多部份都參考了他的講稿，他也提供了授權給我，真ㄉ是太感謝了XD 移動語意是 C++11 新增的一個特性，主要是針對物件導向來做的優化，以淺複製(shallow copy) 代替了深複製(deep copy)。另外，由於移動語意的出現，使原先 C++ 的文法分的更加詳細了，讓編譯器替我們做了更多事，提升了許多效率。 值類別是 C++11 新產生出來的新文法，其實早在 C++03，甚至是 C++98 時就已經有類似的定義了，不過這些定義在 C++11時進行了大改動，並且在 C++17 時，由於 Copy Elision 與 TMC 的緣故，定義又有一次小改動，本文會以 C++17 的定義為主。那由於這是給編譯器看的，是語言的文法部分，所以有時用組語會看不出個所以然，也因此這個東西十分的抽象，據我所知有修過編譯器相關課程的人會比較容易理解，大家需要自己多多消化一下 XD 這篇原本預計是要講移動語意的，但要講移動之前需要先知道值類別是什麼，也許有人會說知道 rvalue、lvalue 就很夠了，但畢竟都要寫了，我就詳細的把全部都寫下來吧，看完整篇文章相信大家也會大概的抓到移動的感覺，對之後理解移動語意肯定有幫助的。 希望這篇文章能幫助大家少翻一點草案，幫大家整理一下重點，同時也希望能讓想深入閱讀的人能夠有中文的資源可以看，畢竟不是每個人都像我一樣閒可以在那邊用破英文慢慢看，大家可以依自己的興趣來跳著看。 Variable、Expression 與 Statement移動語意是一個很大很廣的概念，在看移動語意前我們需要知道「值類別(Value Category)」是什麼。而若要知道什麼是值類別，我們需要先分清楚「變數(Variable)」、「運算式(Expression)」、「陳述式(Statement)」的差別。 這些東西比較偏向程式的文法，那我們就開始吧! 變數 Variable首先大家一開始在學 C++ 都有學過變數，但大家可能沒什麼注意過他的定義，他的定義是這樣的： 變數是一種物件(object)，或者是 non-static data member 的 reference。(來源) 一般在沒有編譯器優化的情況下，宣告一個變數的時候我們會在記憶體裡面挖一塊空間，並在這塊記憶體空間上加上識別字(identifier)，如此一來，我們便能通過這個 identifier 對這個記憶體的位址操作，像是賦值之類的，看看這個例子： 1234567891011#include &lt;iostream&gt;int main() &#123; int a = 4; int b[5]; std::cout &lt;&lt; &quot;&amp;a = &quot; &lt;&lt; &amp;a &lt;&lt; &#x27;
&#x27;; //&amp;a = 0x7f485ffb3c std::cout &lt;&lt; &quot;&amp;b[3] = &quot; &lt;&lt; &amp;b[3]; //&amp;b[3] = 0x7f485ffb2c return 0;&#125; 可以看見我們能過通過 a、b 來對它標記到的記憶體進行操作。 一般來說，「變數」是個內容可更改的物件(除非我們加了 cv 限定詞等綴詞)，但「常量值」不能更改，有時它甚至沒有記憶體位址，變數可以拿來接運算式回傳的值。 另外變數並不一定要有記憶體位址，因為 C++11 後變數的定義多了 Reference，而 Reference 可能沒有記憶體位址。 簡單來說，變數只是一個在妳程式中，能夠存取一個值的識別字(identifier)，至於實際上有沒有 memory allocate 則不是這麼重要，因為這很看編譯器優化與作業系統，但他肯定會有 logic address。 這邊的物件照著 C++ 標準的規定： 在 C++ 中，物件(object) 一定要有 大小 (可以用 sizeof 來檢查) 對齊需求 (可以用 alignof 來檢查) 儲存期限 (自動、靜態、動態、執行緒局部儲存) 生命週期 (暫時或根據儲存期限來決定) 型態(type) 值 (可能是不確定的，像是有預設初始化的 non-class types) 而名字則不一定要有。 運算式 Expression一個運算式由一個以上的運算元(operand) 和運算子組成，用來表示一個計算式，被計算後它可能會「回傳一個結果」，又或可能會有額外的作用(side-effects)，像是 std::printf(&quot;%d&quot;, 4) 會去呼叫 system call，印出一個 4。 讓我們看看下面這些例子： 123456789101142 //一個常數的運算式，回傳4217 + 42 //一個加法的運算式，回傳59int a;a = 23 //一個賦值的運算式，回傳23a + 17 //一個加法的運算式，回傳40static_cast&lt;float&gt;(a) //一個轉型的運算式，回傳「運算式」 a 的floatsizeof a //一個計算byte size的運算式，回傳「運算式」 a 的 byte size[]&#123;return 3;&#125; //一個回傳 3 的 lambda 運算式printf(&quot;Hi!&quot;) //一個有額外作用的運算式，回傳值被捨棄了(discarded-value)，其實它的回傳值是輸出的字數，酷ㄅ 注意我都沒寫分號，因為運算式是一個「組件」，一但加上分號，他就不是一個「組件」，而是一個陳述句了。也因此上面這個程式肯定是無法正常運作的，因為他們都不是陳述句，程式運作的是陳述句。 運算式主要有分「主運算式(Primary Expression)」、「非計算運算式(Unevaluated expressions)」與「棄值運算式(Discarded-value Expression)」，但這不是今天我們的主軸，有興趣的可以到 cppreference 看。 陳述句 Statement最後是陳述句，一個陳述句是程式執行的基本元素，通常最後面會有 ; 來結尾。 陳述句會照順序被執行，它可能會單獨一行出現，但我們也可以利用 &#123;&#125; 將許多陳述句包成一個新的陳述句，這個我們稱它為「複合陳述句(Compound Statement)」。 而運算式通常會是陳述句的一部分，另外，還有一種陳述句叫「運算陳述句(Expression Statement)」，這種陳述句裡面只有運算式。 陳述句有分下面這幾種： 空陳述句 (Null Statement) 運算陳述句 (Expression Statement) 複合陳述句 (Compound Statement) 選擇陳述句 (Selection Statement) 迭代陳述句 (Iteration Statement) 跳躍陳述句 (Jump Statement) 宣告陳述句 (Declaration Statement) 錯誤嘗試區塊 (Try Blocks) 多執行緒區塊 (Atomic and Synchronized Blocks) 要注意的是「宣告」本身就算一個 Statement 而不是 Expression，因此我們無法像這樣做： 123int main() &#123; int a = ( int b = 5 );&#125; 錯誤訊息： 原因是因為 int b = 5 本身就是一個 Statement 了，所以 Compiler 並不希望妳把 int b = 5 放在 int a = 的右邊，它原先預期右邊要是一個 Expression，所以就噴了這個錯。 然後我們將運算陳述句拿出來講一下，因為要分清楚運算式跟陳述句的差別，可以直接用這個例子來看，其實就只差了一個分號，因此一個可執行，一個不行。 其他的大家有興趣可以到 cppreference 上看。 運算陳述句的結構長這樣： expression(optional); attr 是屬性識別字，用來告訴編譯器一些事情，妳可以想像成給編譯器看的註解，可加可不加。 而 expression 就是前面提到的運算式，「可加可不加」，如果不加就會變一個空陳述句，也就是只有一個分號的陳式句，空陳述句通常用來提供 for、while 迴圈一個空的代碼塊(body)，或是一個標籤(label)的代碼塊。 程式裡大部分的陳述句都是運算陳述句，像是賦值或是函式的呼叫等都是。 值類別 Value Categories那麼我們現在知道什麼是淺複製與深複製，也知道變數、運算式和陳述式差在哪了，那我們就可以來討論什麼是 Value Categories 了，首先有一點很重要，那就是值類別是用來判斷運算式的種類的，而不是給物件實體用的，因為超重要，所以講三次，是運算式的種類!! 運算式的種類!! 運算式的種類!!，如果不知道這個，我們接下來講的妳大概也都聽不懂，或者是一知半解了。 運算式有兩種獨立的特性，分別是「Type」和「Value Catories」， Type 不是我們今天討論的主題，我們直接來看 Value Categories。 圖源 Value Categories 主要分三種：Lvalue、Xvalue 和 Prvalue。如果你曾讀過值類別，可能還會聽過 glvalue 與 rvalue，那這兩個又是什麼呢? 這其實與運算式發展的歷史有關，是一個方便記憶而創造出的名詞，glvalue = Lvalue + Xvalue，rvalue = Prvalue + Xvalue。讀到這裡妳可能有點頭花，我們看這兩張圖來方便自己記憶： 圖源圖源 是不是清楚多了，那麼這邊我先將每個的翻譯名稱都給大家，以免之後在閱讀的時候搞混： glvalue：泛左值 rvalue：右值 lvalue：左值 xvalue：將亡值 prvalue：純右值 判斷依據那接下來就來看看這些分類是怎麼分的吧! 主要有兩個判斷依據： 這個運算式回傳的是有身分標識符(identity)的物件嗎? 還是僅僅是個常量值? 如果是有身分標識符的物件，那這個物件的值可以安全的「移動」給別人嗎? 1. 這個運算式回傳的是有身分標識符(identity)的物件嗎? 還是僅僅是個常量值 首先我們先來看一下，什麼叫做 「有身分標識符(identity)」 呢?，有身分標識符表示我們能夠有辦法去證明這個 Expreesion 回傳的物件與另一個 Expression 回傳的物件相，方法隨便，最常見的就是取址，我們看一下這個例子幫大家理解一下什麼叫做「有身分標識符」： 1234567#include &lt;iostream&gt;int main() &#123; int a; std::cout &lt;&lt; &amp;a &lt;&lt; &#x27;
&#x27;; // 0x67bd3ffaec std::cout &lt;&lt; &amp;a &lt;&lt; &#x27;
&#x27;; // 0x67bd3ffaec&#125; 這是個非常直覺的例子，因為 a 是個有記憶體位址的變數，所以上下兩行 a 這個 expression 回傳的物件都是「變數 a」，我們透過取址來證明了這件事。 要注意的是我們會說「有」身分標識符，但並不會特別去提什麼是「身分標識符(identity)」，它是一個概念，並不是像 identifier 這樣有一個東西叫做 identifier。 那麼接下來我們大略的看一下一些例子，讓大家感受一下那個感覺： 123456789101112131415int a;a //擁有 identitya + 2 //沒有identitya || true //沒有identitya++ //沒有identity++a //擁有identity42 //沒有 identitynullptr //沒有 identityfalse //沒有 identity[]&#123;return 42;&#125; //沒有 identity&quot;Hello world&quot; //擁有 identity!!std::cout //擁有 identity，std::cout 是 std::ostream 的 instancestatic_cast&lt;int&gt;(a) //沒有 identitystd::move(a) //擁有 identity 2. 如果是有身分標識符的物件，那這個物件的值可以安全的「移動」給別人嗎 再來看第二點，那麼什麼時候運算式回傳的物件可以安全的「移動」給別人呢? 如果這個物件是個匿名的「暫時」物件，或者這個物件的生命週期快要結束了，我們就稱它可以安全的「移動」給別人，是不是已經有一點移動語意的感覺了ㄋ? 沒錯，這94移動語意的核心，讓我們來看看接下來的例子： 123456789101112131415#include &lt;iostream&gt;#include &lt;vector&gt;std::string func() &#123; return &quot;Steal me!&quot;;&#125;int main() &#123; std::vector&lt;std::string&gt; vec; vec.push_back( func() ); std::string x&#123; &quot;Steal me!&quot; &#125;; vec.push_back( std::move( x ) ); return 0;&#125; func() 會回傳一個字串，而我們想要將這個回傳的字串推入 vector，現在問題來了，這個字串能不能安全的「移動」給別人呢? 如果可以，那麼我們將可以少一次的複製，因為我們可以直接將這個字串「移動」進 vector，，而不是複製一個一樣的字串後推入 vector。 那麼這邊答案是可以! 因為 func() 回傳的字串在 push_back() 後就要被解構了，因此我們可以將他的資源接收過來，而不是複製後再將 func() 的字串解構。 再來下面有另一個例子，我們有個 std::string x，並且我們想將他「移動」進 vector，原本不應該可以移動的，因為 std::string x 等等並不會被解構，但我們可以利用 std::move(x) 來讓他強制「移動」。 原則上來講，如果一個物件僅僅是為了「傳遞」資訊，或「暫時存取」某個東西，而不是用來「儲存」某些資訊的，那麼他就不可被「移動」。 那麼這樣我們就可以開始看什麼是 Lvalue、Prvalue 與 Xvalue 了! Lvalue ExpressionLvalue，中文翻作左值，一個 Lvalue Expression 回傳的物件擁有「身分標識符(identity)」，並且在正常的情況下它不該被「移動」，只能複製。 這代表一個 Lvalue Expression 回傳的物件會有一個記憶體位址，用途常會類似是「儲存」一個東西，像變數一樣。 我們能夠透過這個名稱，在它「生成出來的那行外」來使用這塊記憶體內的東西。 我們看看 Stackoverflow 上的一個 例子： 12345678910111213141516171819202122232425262728#include &lt;iostream&gt;int i = 7;const int&amp; f() &#123; return i;&#125;int main() &#123; std::cout&lt;&lt;&amp;&quot;www&quot;&lt;&lt;std::endl; //0x7ff7c0ca5050 std::cout&lt;&lt;&amp;&quot;www&quot;&lt;&lt;std::endl; //0x7ff7c0ca5050 i; i; int* p_i = new int(7); *p_i; *p_i; const int&amp; r_I = 7; r_I; r_I; f(); i; return 0;&#125; 第 10 行的 &quot;www&quot; 是 Lvalue expression，因為它回傳的物件與第 11 行的 &quot;www&quot; 是同一個，它回傳的物件的用處是「儲存」一段文字，並且可以「在外部呼叫」。 第 13 行的 i 是 Lvalue expression，因為它回傳的物件與第 14 行的 i 是同一個，它回傳的物件的用處是「儲存」一個整數，並且可以「在外部呼叫」。 第 17 行的 *p_i 是 Lvalue expression，因為它回傳的物件與第 18 行的 *p_i 是同一個，它回傳的物件的用處是「儲存」一個我們 new 出來的整數，並且可以「在外部呼叫」。 第 21 行的 r_I 是 Lvalue expression，因為它回傳的物件與第 22 行的 r_I 是同一個，它回傳的物件的用處是「儲存」一個整數，並且可以「在外部使用」。 第 24 行的 f() 是 Lvalue expression，因為它回傳的物件與第 25 行的 i 是同一個，它回傳的物件的用處是「儲存」一個整數，並且可以「在外部使用」。 不知道大家有沒有感受到那個精神，小心不要把他們想成 variable，因為這邊講的是文法，而不是在說記憶體內部的分配，所以他們是 expression，不是variable。 種類那 Lvalue Expression 有以下這些 (來源)： 變數的名稱、函式本體、模板參數物件(C++20)、或一個資料成員，像是 std::cin 或 std::endl。 函式本體的位址我們可以這樣印出來看： 12345678#include &lt;iostream&gt;int f() &#123; return 0; &#125;;int main() &#123; std::cout &lt;&lt; f &lt;&lt; &#x27;
&#x27;; //1 std::cout &lt;&lt; reinterpret_cast&lt;void *&gt;( f ); //0x7ff6292217e0&#125; 不能直接印出來看的原因是 ostream 的 &lt;&lt; 並沒有重載函式指標，但在標準中規範了函式指標可以隱式轉換成布林值，並且布林值會是 true (來源1)、(來源2)，因此我們需要將其轉換為 void* 或其他指標型態才能把它印出來看。 而 模板參數物件(C++20) 則是有靜態的儲存位址，所以是 Lvalue Expression。 回傳 Lvalue Reference 的運算子重載或函式呼叫(function call)，像是 std::getline(std::cin, str) ， std::cout &lt;&lt; 1 ， str1 = str2 或 ++it 等等。 利用了賦值運算子或複合賦值運算子的運算式，像是a = b、a += b、a %= b。 利用了間接取值運算子的運算式，像是 *p。 利用了 注標運算子 的運算式，像是 a[n]、p[n] ，但注意 a 要是一個陣列左值，不能是 陣列右值 之類的東西 利用了 成員物件訪問運算子 的運算式，像是 a.m，但 m 不能是 enum 的成員、某些非靜態的成員函式，或一個 class prvalue 內的非靜態成員(以上例來說就是 a 是 class prvalue 且 m 是非靜態成員)。 class prvalue 和 array rvalue 可以看這個例子，我有稍微改一下： 123456789101112131415161718192021222324252627282930313233343536 #include &lt;iostream&gt;#include &lt;type_traits&gt;#include &lt;utility&gt;// x 可以是 xvalue 或 prvalue 的參考 (因為他是rvalue reference)void f( int( &amp;&amp;rr )[2][3] ) &#123; std::cout &lt;&lt; &quot; &quot; &lt;&lt; sizeof( rr ) &lt;&lt; &#x27;
&#x27;;&#125;struct X &#123; X() &#123; std::cout &lt;&lt; &quot; X()&quot; &lt;&lt; &#x27;
&#x27;; &#125; int i[2][3]; ~X() &#123; std::cout &lt;&lt; &quot; ~X()&quot; &lt;&lt; &#x27;
&#x27;; &#125;&#125;;template &lt;typename T&gt;using identity = T;int main() &#123; std::cout &lt;&lt; &quot;sizeof( X().i ) = &quot; &lt;&lt; sizeof( X().i ) &lt;&lt; &#x27;
&#x27;; // size of the array std::cout &lt;&lt; &quot;
 now call f( X().i )
&quot;; f( X().i ); // okay: rr binds to xvalue // f(x.i); // error: cannot bind to lvalue int a[2][3]; std::cout &lt;&lt; &quot;
 now call f( std::move( a ) )
&quot;; f( std::move( a ) ); // okay: rr binds to xvalue using arr_t = int[2][3]; std::cout &lt;&lt; &quot;
 now call f( arr_t&#123;&#125; )
&quot;; f( arr_t&#123;&#125; ); // okay: rr binds to prvalue std::cout &lt;&lt; &quot;
 now callf( identity&lt;int[][3]&gt;&#123; &#123; 1, 2, 3 &#125;, &#123; 4, 5, 6 &#125; &#125; )
&quot;; f( identity&lt;int[][3]&gt;&#123; &#123; 1, 2, 3 &#125;, &#123; 4, 5, 6 &#125; &#125; ); // okay: rr binds to prvalue&#125; 看不懂的話可以等後面的TMC、Copy Elision、RVO讀完後再回來看一次。 部分利用了 成員指標訪問運算子 的運算式，像是 p-&gt;m，但 m 不能是 enum 的成員或某些非靜態的成員函式。 部分利用了指向「資料成員」(物件) 的 成員指標運算子 的運算式，像是 a.*mp，a 是一個 lvalue 且 mp 是一個「資料成員」的指標。 部分利用了指向成員「指標」的 成員指標運算子 的運算式，像是 p-&gt;*mp，mp 是一個「資料成員」的指標。 利用了 逗號運算子 的運算式，像是 a, b ，b 要是一個 lvalue。 (待補) 部分利用了 三元運算子 的運算式。 字串常量 (string literal)，像是 &quot;Hello World&quot;。 因為字串常量其實像是一個靜態成員，在整個程式結束前都會被存在某個唯讀的記憶體區段。 轉型(cast)成 lvalue reference 型態的運算式，像是 static_cast&lt;int&amp;&gt;(x)。 轉型(cast)成「函式型態」的 rvalue reference 的運算式，像是 static_cast&lt;void (&amp;&amp;)(int)&gt;(x) 回傳「函式」的 rvalue reference 的函式呼叫(function call)。 特性那麼 Lvalue Expression 有一些特性，有些是只有 Lvalue Expression 有的，有些是 Xvalue Expression 也有的 (換句話說就是 glvalue 有的) 僅限 Lvalue Expression 擁有的特性: 可以被取址 取址運算符 &amp; 的後方必須要接上 Lvalue Expression 或一個 Qualified-id (來源)。 一個可更改的 Lvalue Expression 可以擺在賦值運算子和複合賦值運算子的左邊。 Lvalue Expression 可以拿來初始化 lvalue reference，這個動作會給被連結到的物件一個新的識別字(identifier) Xvalue Expression 也有的特性 可被隱式轉換成 prvalue，像是「Lvalue 與 Prvalue的隱式轉換」、「陣列與指標的隱式轉換」、「函式與指標的隱式轉換」 可能是 多形 的，它標識的對象的 動態類型 不一定是表達式的靜態類型。 如果某個 Lvalue Expression 或 Xvalue Expression 指向了 多形 的物件，那麼它衍生的型態(子類)我們稱它為 動態類型 : 123456struct B &#123; virtual ~B() &#123;&#125; &#125;; // polymorphic typestruct D: B &#123;&#125;; // polymorphic typeD d; // most-derived objectB* ptr = &amp;d;// the static type of (*ptr) is B// the dynamic type of (*ptr) is D 想知道詳細狀況可以去讀 執行期型態訊息 (RTTI) 的操作。 在表達式合法的情況下可以是 不完全型態。 Xvalue ExpressionXvalue，中文翻作將亡值，一個 Xvalue Expression 回傳的物件擁有「身分標識符(identity)」，但是它通常用來「暫時儲存」某個東西。 這代表一個 Xvalue Expression 回傳的物件會有一個記憶體位址，但我們不能夠在它「生成出來的那行外」來使用這塊記憶體內的東西。 我們看一下這個例子: 12345678910111213141516#include &lt;iostream&gt;struct X &#123; X() &#123; std::cout &lt;&lt; &quot; X()&quot; &lt;&lt; &#x27;
&#x27;; std::cout &lt;&lt; &quot;sizeof(*this) = &quot; &lt;&lt; sizeof( *this ) &lt;&lt; &#x27;
&#x27;; std::cout &lt;&lt; &quot;this = &quot; &lt;&lt; this &lt;&lt; &#x27;
&#x27;; &#125; int i; ~X() &#123; std::cout &lt;&lt; &quot; ~X()&quot; &lt;&lt; &#x27;
